const { chromium } = require('playwright');

(async () => {
  // Connect to the running browser via CDP
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const contexts = browser.contexts();
  const page = contexts[0].pages()[0] || await contexts[0].newPage();

  console.log('当前页面:', page.url());

  // Navigate to CRM homepage
  await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'networkidle' }).catch(() => {});
  await page.waitForTimeout(3000);

  console.log('导航后页面:', page.url());
  console.log('页面标题:', await page.title());

  // Take a screenshot
  await page.screenshot({ path: 'okki_crm_home.png', fullPage: false });
  console.log('截图已保存');

  // Get page content structure
  const text = await page.evaluate(() => document.body.innerText.substring(0, 3000));
  console.log('页面文本内容:\n', text);

  await browser.close();
})().catch(err => {
  console.error('Error:', err);
  process.exit(1);
});

