const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  console.log('当前URL:', page.url());
  console.log('标题:', await page.title());

  // Wait a moment for content to load
  await page.waitForTimeout(2000);

  // Get all visible text from the chat area
  const text = await page.evaluate(() => document.body.innerText);
  console.log('=== 页面全部文本 ===\n', text);

  // Also look specifically for chat message elements
  const chatContent = await page.evaluate(() => {
    // Common chat message selectors
    const selectors = [
      '[class*="message"]', '[class*="chat"]', '[class*="talk"]',
      '[class*="msg"]', '[class*="dialog"]', '[class*="conversation"]',
      '.message-content', '.msg-content', '.chat-content'
    ];
    const results = {};
    selectors.forEach(sel => {
      const els = document.querySelectorAll(sel);
      if (els.length > 0) {
        results[sel] = Array.from(els).map(el => el.textContent.trim()).filter(t => t);
      }
    });
    return results;
  });
  console.log('\n=== 聊天相关元素 ===');
  Object.entries(chatContent).forEach(([sel, texts]) => {
    if (texts.length > 0) {
      console.log(`\n[${sel}]:`);
      texts.forEach(t => console.log(`  ${t.substring(0, 200)}`));
    }
  });

})().catch(err => {
  console.error('Error:', err);
  process.exit(1);
});

