const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  console.log('当前URL:', page.url());
  console.log('Frames数量:', page.frames().length);

  // Check all frames
  for (const frame of page.frames()) {
    console.log('\n--- Frame:', frame.url().substring(0, 200), '---');
    try {
      const text = await frame.evaluate(() => document.body?.innerText?.substring(0, 3000) || 'no body');
      console.log('内容:', text);
    } catch (e) {
      console.log('无法访问:', e.message.substring(0, 100));
    }
  }

  // Also check the main page for any clickable customer/chat items
  const clickable = await page.evaluate(() => {
    const items = [];
    document.querySelectorAll('*').forEach(el => {
      const text = (el.textContent || '').trim();
      if (text && text.length < 100 && el.children.length === 0 && el.offsetWidth > 0) {
        const rect = el.getBoundingClientRect();
        const styles = window.getComputedStyle(el);
        if (rect.top > 50 && rect.top < 500 && !['SCRIPT','STYLE'].includes(el.tagName)) {
          items.push({
            tag: el.tagName,
            text: text.substring(0, 60),
            top: Math.round(rect.top),
            left: Math.round(rect.left),
            width: Math.round(rect.width),
            height: Math.round(rect.height),
            cursor: styles.cursor
          });
        }
      }
    });
    return items.slice(0, 100);
  });
  console.log('\n=== 可见文字元素 ===');
  clickable.forEach(el => {
    console.log(`"${el.text}" (${el.tag}) at (${el.left},${el.top}) ${el.width}x${el.height} cursor:${el.cursor}`);
  });

})().catch(err => {
  console.log('Error:', err);
});

