const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.connectOverCDP('http://127.0.0.1:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // Check all iframes in the main page
  const frameInfo = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('iframe')).map(f => ({
      src: f.src,
      id: f.id,
      className: f.className?.substring(0, 50),
      width: f.width,
      height: f.height
    }));
  });
  console.log('Iframes:', JSON.stringify(frameInfo, null, 2));

  // Try to access frame by index
  const frames = page.frames();
  console.log('Total frames:', frames.length);
  for (let i = 0; i < frames.length; i++) {
    console.log(`Frame ${i}:`, frames[i].url().substring(0, 200));
    try {
      const content = await frames[i].evaluate(() => document.body?.innerHTML?.substring(0, 1000) || 'no body');
      if (content.length > 100) {
        console.log(`  HTML preview: ${content.substring(0, 500)}`);
      }
    } catch(e) {
      console.log(`  Error: ${e.message.substring(0, 100)}`);
    }
  }

  // Also try to search for "rehema" in entire page
  const hasRehema = await page.evaluate(() => document.body.innerText.includes('rehema'));
  console.log('Has "rehema" text:', hasRehema);

  // Search all child frames recursively
  async function getAllText(f, depth = 0) {
    if (depth > 5) return '';
    try {
      let text = await f.evaluate(() => document.body?.innerText || '').catch(() => '');
      for (const child of f.childFrames()) {
        text += '\n' + await getAllText(child, depth + 1);
      }
      return text;
    } catch { return ''; }
  }

  const allText = await getAllText(page);
  console.log('All text contains rehema:', allText.toLowerCase().includes('rehema'));
  if (allText.includes('rehema')) {
    const idx = allText.toLowerCase().indexOf('rehema');
    console.log('Context around rehema:', allText.substring(Math.max(0, idx-200), idx+500));
  }

})().catch(err => {
  console.log('Fatal:', err.message?.substring(0, 300));
});

